-- Migracion 043: agrega el placement 'financiacion' a la tabla promotions
-- y carga las 69 imagenes de promos con precios (carpeta CATALOGO PROMOS,
-- subcarpetas JUNIO y MARKET) para la nueva seccion "Equipa tu negocio con
-- estas promos en financiacion" de la home. Promos vigentes de julio, hasta
-- agotar stock. Administrables desde /admin/promociones (placement
-- "Promos en financiacion").

alter table promotions drop constraint if exists promotions_placement_check;
alter table promotions add constraint promotions_placement_check
  check (placement in ('hero','banner','strip','financiacion'));

